/**
 * The `deployMetadata` step collects deploy-specific metadata generated by the build process and
 * writes it to disk as a build artifact. This metadata is used by the deploy process (`netlify
 * deploy` in non-Netlify Build environments and by the core deploy step in a Netlify Build
 * environment) to augment the deployment, e.g. to inject deploy-specific environment variables.
 *
 * Ideally, we could avoid writing this metadata to disk entirely. However, to support local flows,
 * where the deploy process can happen out-of-band with the build flow (a `netlify build` followed--
 * sometimes much later--by a `netlify deploy`), this information needs to be accessible to separate
 * processes.
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { log, logError } from '../../log/logger.js'
import { DeployMetadataSchema, getDeployMetadataPath } from '../../utils/deploy_metadata.js'
import type { CoreStep, CoreStepFunction } from '../types.js'

const coreStep: CoreStepFunction = async function ({
  buildDir,
  deployEnvVars,

  debug,
  logs,
  quiet,
}) {
  const deployMetadataPath = getDeployMetadataPath(buildDir)

  if (debug && !quiet) {
    log(logs, `Writing deploy metadata to ${deployMetadataPath}...`)
  }

  // Do one last final validation of the metadata file's contents and normalize it
  const parseResult = DeployMetadataSchema.safeParse({ environment: deployEnvVars })
  if (!parseResult.success) {
    logError(logs, 'Invalid deploy metadata')
    throw new Error('Invalid deploy metadata')
  }
  const serializedData = JSON.stringify(parseResult.data, null, 2)
  try {
    await fs.mkdir(path.dirname(deployMetadataPath), { recursive: true })
    await fs.writeFile(deployMetadataPath, serializedData, { encoding: 'utf8' })
  } catch (err) {
    console.log('OH. NO.')
    logError(logs, 'Failed to write deploy metadata')
    throw new Error('Failed to write deploy metadata', { cause: err })
  }

  if (debug && !quiet) {
    log(logs, `Wrote deploy metadata to ${deployMetadataPath}.`)
  }

  return {}
}

export const deployMetadata: CoreStep = {
  event: 'onPostBuild',
  coreStep,
  coreStepId: 'deploy_metadata',
  coreStepName: 'Deploy metadata',
  coreStepDescription: () => 'Write deploy metadata',
}
